mapper.select:
select c.id, c.name as name, c.room, c.subject, c.begin_date, c.end_date, c.master_id, e.name as master_name, c.create_time, c.update_time, (case when c.end_date < now() then '已结课' when c.begin_date > now() then '未开班' else '在读中' end) as status from clazz as c left join emp as e on c.master_id = e.id
c.name like concat('%', #{name}, '%')
and c.begin_date between #{begin} and #{end} and c.end_date between #{begin} and #{end}
